CREATE OR REPLACE FUNCTION public.admin_analytics(p_from timestamp with time zone, p_to timestamp with time zone)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare result jsonb;
begin
 if not public.btv_is_admin() then raise exception 'Administrator access required'; end if;
 select jsonb_build_object(
  'users',jsonb_build_object(
   'total',(select count(*) from profiles),'new',(select count(*) from profiles where created_at>=p_from and created_at<p_to),
   'free',(select count(*) from profiles where account_type='free'),'premium',(select count(*) from profiles where account_type='premium'),
   'suspended',(select count(*) from user_status where status='suspended')),
  'questions',jsonb_build_object('cbt',(select count(*) from cbt_questions),'nclex',(select count(*) from nclex_questions)),
  'learning',jsonb_build_object(
   'cbt_attempts',(select count(*) from cbt_attempts where attempted_at>=p_from and attempted_at<p_to),
   'nclex_attempts',(select count(*) from nclex_attempts where attempted_at>=p_from and attempted_at<p_to),
   'mock_exams',(select (select count(*) from mock_exam_results where completed_at>=p_from and completed_at<p_to)+(select count(*) from nclex_exam_results where completed_at>=p_from and completed_at<p_to)),
   'videos_watched',(select count(*) from video_progress where last_watched_at>=p_from and last_watched_at<p_to),
   'videos_completed',(select count(*) from video_progress where completed and last_watched_at>=p_from and last_watched_at<p_to)),
  'bookings',jsonb_build_object('created',(select count(*) from bookings where created_at>=p_from and created_at<p_to),'completed',(select count(*) from bookings where status='completed' and updated_at>=p_from and updated_at<p_to),'cancelled',(select count(*) from bookings where status='cancelled' and updated_at>=p_from and updated_at<p_to),'no_show',(select count(*) from bookings where status='no_show' and updated_at>=p_from and updated_at<p_to)),
  'payments',jsonb_build_object(
   'revenue_minor',(select coalesce(sum(amount_minor),0) from booking_payments where status='successful' and verified_at>=p_from and verified_at<p_to),
   'successful',(select count(*) from booking_payments where status='successful' and created_at>=p_from and created_at<p_to),
   'pending',(select count(*) from booking_payments where status='pending' and created_at>=p_from and created_at<p_to),
   'failed',(select count(*) from booking_payments where status='failed' and created_at>=p_from and created_at<p_to)),
  'activity',jsonb_build_object('zibur',(select count(*) from app_events where event_name='zibur_message' and created_at>=p_from and created_at<p_to),'documents',(select count(*) from app_events where event_name='document_upload' and created_at>=p_from and created_at<p_to),'active_users',(select count(distinct user_id) from app_events where created_at>=p_from and created_at<p_to))
 ) into result;
 return result;
end $function$
;

CREATE OR REPLACE FUNCTION public.admin_list_users(p_search text DEFAULT ''::text, p_plan text DEFAULT NULL::text, p_status text DEFAULT NULL::text, p_limit integer DEFAULT 50, p_offset integer DEFAULT 0)
 RETURNS TABLE(id uuid, email text, full_name text, profession text, destination text, account_type text, role text, status text, created_at timestamp with time zone, last_sign_in_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
 select p.id,u.email,p.full_name,p.profession,p.destination,p.account_type,p.role,coalesce(s.status,'active'),p.created_at,u.last_sign_in_at
 from public.profiles p join auth.users u on u.id=p.id left join public.user_status s on s.user_id=p.id
 where public.btv_is_admin()
 and (p_search='' or coalesce(p.full_name,'') ilike '%'||p_search||'%' or coalesce(u.email,'') ilike '%'||p_search||'%')
 and (p_plan is null or p.account_type=p_plan) and (p_status is null or coalesce(s.status,'active')=p_status)
 order by p.created_at desc limit least(greatest(p_limit,1),200) offset greatest(p_offset,0)
$function$
;

CREATE OR REPLACE FUNCTION public.admin_set_user_access(p_user uuid, p_plan text, p_status text, p_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
 if not public.btv_is_admin() then raise exception 'Administrator access required'; end if;
 if p_plan not in ('free','premium') or p_status not in ('active','suspended') then raise exception 'Invalid access value'; end if;
 update public.profiles set account_type=p_plan,updated_at=now() where id=p_user and role<>'admin';
 insert into public.user_status(user_id,status,reason,suspended_at,suspended_by,updated_at)
 values(p_user,p_status,p_reason,case when p_status='suspended' then now() end,case when p_status='suspended' then auth.uid() end,now())
 on conflict(user_id) do update set status=excluded.status,reason=excluded.reason,suspended_at=excluded.suspended_at,suspended_by=excluded.suspended_by,updated_at=now();
 insert into public.admin_audit_logs(admin_id,action,target_type,target_id,details)
 values(auth.uid(),'set_user_access','user',p_user::text,jsonb_build_object('plan',p_plan,'status',p_status,'reason',p_reason));
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_audit_admin_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare row_data jsonb; row_id text;
begin
 if not btv_is_admin() then return coalesce(new,old);end if;
 row_data=case when tg_op='DELETE' then to_jsonb(old) else to_jsonb(new) end;
 row_id=coalesce(row_data->>'id',row_data->>'code',row_data->>'user_id');
 insert into admin_audit_logs(actor_id,action,target_type,target_id,details)values(auth.uid(),lower(tg_op),tg_table_name,row_id,jsonb_build_object('record',row_data));
 return coalesce(new,old);
end $function$
;

