 select exists(select 1 from profiles p where p.id=auth.uid() and lower(coalesce(p.role,''))='admin')
 or exists(select 1 from btv_admin_permissions a where a.user_id=auth.uid() and a.is_active and (a.admin_role='super_admin' or p_permission=any(a.permissions)));
