CREATE OR REPLACE FUNCTION public.btv_admin_adjust_wallet(p_user uuid, p_amount integer, p_reason text, p_key text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare new_balance integer;
begin
  if not public.btv_is_admin() then raise exception 'Administrator access required'; end if;
  if p_amount=0 or nullif(trim(p_reason),'') is null or nullif(trim(p_key),'') is null then raise exception 'Invalid adjustment'; end if;
  perform public.btv_bootstrap_user(p_user);
  update public.btv_wallets set balance=balance+p_amount,
    lifetime_earned=lifetime_earned+greatest(p_amount,0), lifetime_spent=lifetime_spent+greatest(-p_amount,0), updated_at=now()
  where user_id=p_user and balance+p_amount>=0 returning balance into new_balance;
  if new_balance is null then raise exception 'Adjustment would create an invalid balance'; end if;
  insert into public.btv_wallet_transactions(user_id,amount,balance_after,transaction_type,description,idempotency_key)
  values(p_user,p_amount,new_balance,'admin_adjustment',left(trim(p_reason),300),'admin:'||p_key)
  on conflict(user_id,idempotency_key) do nothing;
  return new_balance;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_admin_refund_exam(p_attempt_id uuid, p_reason text, p_key text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare v_attempt btv_exam_attempts%rowtype; v_wallet btv_wallets%rowtype; v_balance integer; v_before integer;
begin
 if not btv_is_admin() then raise exception using message='ADMIN_REQUIRED'; end if;
 if nullif(trim(p_reason),'') is null or nullif(trim(p_key),'') is null then raise exception using message='REFUND_REASON_REQUIRED'; end if;
 select * into v_attempt from btv_exam_attempts where id=p_attempt_id for update;
 if not found then raise exception using message='ATTEMPT_NOT_FOUND'; end if;
 select * into v_wallet from btv_wallets where user_id=v_attempt.user_id for update; v_before:=v_wallet.balance;
 if exists(select 1 from btv_wallet_transactions where user_id=v_attempt.user_id and idempotency_key='exam-refund:'||v_attempt.id) then return v_before; end if;
 update btv_wallets set balance=balance+v_attempt.coin_price_paid,lifetime_earned=lifetime_earned+v_attempt.coin_price_paid,updated_at=now() where user_id=v_attempt.user_id returning balance into v_balance;
 insert into btv_wallet_transactions(user_id,wallet_id,amount,balance_before,balance_after,transaction_type,source_type,source_id_text,description,idempotency_key,metadata)
 values(v_attempt.user_id,v_attempt.user_id,v_attempt.coin_price_paid,v_before,v_balance,'exam_refund','refund',v_attempt.id::text,left(trim(p_reason),300),'exam-refund:'||v_attempt.id,jsonb_build_object('admin_id',auth.uid(),'admin_key',p_key));
 update btv_exam_attempts set status='refunded',updated_at=now() where id=v_attempt.id; return v_balance;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_approve_mock_refund(p_request_id uuid, p_approve boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  r public.btv_mock_refund_requests%rowtype;
  s public.btv_mock_sessions%rowtype;
  v_balance_before integer;
  v_balance_after integer;
begin
  if not public.btv_is_admin() then
    raise exception 'Administrator access required';
  end if;

  select *
  into r
  from public.btv_mock_refund_requests
  where id = p_request_id
  for update;

  if not found or r.status <> 'pending' then
    raise exception 'Refund request is unavailable';
  end if;

  select *
  into s
  from public.btv_mock_sessions
  where id = r.session_id
  for update;

  if not found then
    raise exception 'Mock session not found';
  end if;

  if p_approve then
    select balance
    into v_balance_before
    from public.btv_wallets
    where user_id = r.user_id
    for update;

    if not found then
      raise exception 'Wallet not found for refund recipient';
    end if;

    update public.btv_wallets
    set
      balance = balance + s.coin_cost,
      lifetime_earned = lifetime_earned + s.coin_cost,
      updated_at = now()
    where user_id = r.user_id
    returning balance into v_balance_after;

    insert into public.btv_wallet_transactions(
      wallet_id,
      user_id,
      amount,
      balance_before,
      balance_after,
      transaction_type,
      description,
      reference_type,
      reference_id,
      idempotency_key,
      metadata
    )
    values (
      r.user_id,
      r.user_id,
      s.coin_cost,
      v_balance_before,
      v_balance_after,
      'mock_refund',
      'Approved technical refund',
      'mock_session',
      s.id,
      'mock-refund:' || s.id,
      jsonb_build_object(
        'session_id', s.id,
        'refund_request_id', r.id
      )
    )
    on conflict (user_id, idempotency_key) do nothing;

    update public.btv_mock_sessions
    set status = 'refunded'
    where id = s.id;
  end if;

  update public.btv_mock_refund_requests
  set
    status = case
      when p_approve then 'approved'
      else 'rejected'
    end,
    reviewed_by = auth.uid(),
    reviewed_at = now()
  where id = r.id;
end;
$function$
;

