 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin perform btv_bootstrap_user(new.id); return new; end $function$
;

CREATE OR REPLACE FUNCTION public.btv_book_mentor(p_mentor_id uuid, p_availability_id uuid, p_topic text)
 RETURNS TABLE(booking_id uuid, balance integer, coin_cost integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  m public.btv_mentors%rowtype;
  a public.btv_mentor_availability%rowtype;
  w public.btv_wallets%rowtype;
  bid uuid;
  v_balance_before integer;
begin
  if uid is null then
    raise exception 'Authentication required';
  end if;

  perform public.btv_bootstrap_user(uid);

  select *
  into m
  from public.btv_mentors
  where id = p_mentor_id
    and status = 'approved';

  if not found then
    raise exception 'Mentor unavailable';
  end if;

  select *
  into a
  from public.btv_mentor_availability
  where id = p_availability_id
    and mentor_id = m.id
    and is_booked = false
    and starts_at > now()
  for update;

  if not found then
    raise exception 'Time unavailable';
  end if;

  select *
  into w
  from public.btv_wallets
  where user_id = uid
  for update;

  if not found then
    raise exception 'Wallet not found';
  end if;

  if w.balance < m.coin_price then
    raise exception
      'INSUFFICIENT_BC:%:%',
      m.coin_price,
      w.balance;
  end if;

  v_balance_before := w.balance;

  insert into public.btv_mentor_bookings(
    user_id,
    mentor_id,
    availability_id,
    coin_cost,
    topic,
    starts_at
  )
  values (
    uid,
    m.id,
    a.id,
    m.coin_price,
    left(p_topic, 500),
    a.starts_at
  )
  returning id into bid;

  update public.btv_mentor_availability
  set is_booked = true
  where id = a.id;

  update public.btv_wallets
  set
    balance = balance - m.coin_price,
    lifetime_spent = lifetime_spent + m.coin_price,
    updated_at = now()
  where user_id = uid
  returning * into w;

  insert into public.btv_wallet_transactions(
    wallet_id,
    user_id,
    amount,
    balance_before,
    balance_after,
    transaction_type,
    description,
    reference_type,
    reference_id,
    idempotency_key,
    metadata
  )
  values (
    uid,
    uid,
    -m.coin_price,
    v_balance_before,
    w.balance,
    'mentor_charge',
    'Mentor session',
    'mentor_booking',
    bid,
    'mentor-charge:' || bid,
    jsonb_build_object(
      'mentor_id', m.id,
      'booking_id', bid,
      'availability_id', a.id
    )
  );

  return query
  select
    bid,
    w.balance,
    m.coin_price;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.btv_bootstrap_user(p_user uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_wallet_created uuid;
  v_balance integer;
begin
  -- Create a wallet only when the user does not already have one.
  insert into public.btv_wallets(user_id)
  values (p_user)
  on conflict (user_id) do nothing
  returning user_id into v_wallet_created;

  select balance
  into v_balance
  from public.btv_wallets
  where user_id = p_user;

  if not found then
    raise exception 'Unable to create or locate wallet for user %', p_user;
  end if;

  -- Only create a welcome transaction when a new wallet was created.
  if v_wallet_created is not null then
    insert into public.btv_wallet_transactions(
      wallet_id,
      user_id,
      amount,
      balance_before,
      balance_after,
      transaction_type,
      description,
      idempotency_key,
      metadata
    )
    values (
      p_user,
      p_user,
      150,
      0,
      v_balance,
      'welcome',
      'Welcome to Beyond The Visa — 150 Beyond Coins',
      'welcome-bonus',
      '{}'::jsonb
    )
    on conflict (user_id, idempotency_key) do nothing;
  end if;

  insert into public.btv_gamification(user_id)
  values (p_user)
  on conflict (user_id) do nothing;

  insert into public.btv_notification_preferences(user_id)
  values (p_user)
  on conflict (user_id) do nothing;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.btv_claim_coin_opportunity(p_code text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare uid uuid:=auth.uid(); opportunity public.btv_coin_opportunities%rowtype; eligible boolean:=false; new_balance integer;
begin
 if uid is null then raise exception 'Authentication required'; end if;
 select * into opportunity from public.btv_coin_opportunities where code=p_code and is_active and (starts_at is null or starts_at<=now()) and (ends_at is null or ends_at>=now());
 if not found then raise exception 'Opportunity unavailable'; end if;
 if opportunity.validation_type='profile_complete' then select count(*)>0 into eligible from public.profiles where id=uid;
 elsif opportunity.validation_type='first_mock' then select exists(select 1 from public.btv_mock_sessions where user_id=uid and status='completed') into eligible;
 elsif opportunity.validation_type='study_streak' then select coalesce(current_streak,0)>=7 into eligible from public.btv_gamification where user_id=uid;
 elsif opportunity.validation_type='journey_percent' then select coalesce(count(*) filter(where p.completed),0)*100>=greatest(count(*),1)*50 into eligible from public.btv_journey_steps s left join public.btv_user_journey_progress p on p.step_code=s.code and p.user_id=uid where s.is_active;
 end if;
 if not eligible then raise exception 'Complete this activity before claiming the reward'; end if;
 insert into public.btv_coin_rewards(user_id,opportunity_code,coin_amount,evidence) values(uid,p_code,opportunity.coin_reward,jsonb_build_object('validated_at',now())) on conflict(user_id,opportunity_code) do nothing;
 if not found then select balance into new_balance from public.btv_wallets where user_id=uid; return new_balance; end if;
 perform public.btv_bootstrap_user(uid);update public.btv_wallets set balance=balance+opportunity.coin_reward,lifetime_earned=lifetime_earned+opportunity.coin_reward,updated_at=now() where user_id=uid returning balance into new_balance;
 insert into public.btv_wallet_transactions(user_id,amount,balance_after,transaction_type,description,reference_type,idempotency_key) values(uid,opportunity.coin_reward,new_balance,'reward',opportunity.title,'coin_opportunity','reward:'||p_code) on conflict(user_id,idempotency_key) do nothing;
 return new_balance;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_complete_mock(p_session_id uuid, p_score numeric, p_time_used integer, p_answers jsonb DEFAULT '{}'::jsonb, p_estimated_band numeric DEFAULT NULL::numeric)
 RETURNS public.btv_mock_sessions
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare uid uuid:=auth.uid(); s btv_mock_sessions%rowtype; xp_gain integer:=100;
begin
 update btv_mock_sessions set status='completed',score=p_score,time_used_seconds=greatest(0,p_time_used),answers=coalesce(p_answers,'{}'),estimated_band=p_estimated_band,completed_at=now()
 where id=p_session_id and user_id=uid and status='active' returning * into s;
 if not found then select * into s from btv_mock_sessions where id=p_session_id and user_id=uid; return s; end if;
 insert into btv_study_activity(user_id,activity_type,exam_type,questions_answered,correct_answers,study_seconds,score,metadata)
 select uid,'mock_completed',c.exam_type,coalesce(c.question_count,0),round(coalesce(c.question_count,0)*coalesce(p_score,0)/100),greatest(0,p_time_used),p_score,jsonb_build_object('session_id',p_session_id)
 from btv_mock_catalog c where c.id=s.catalog_id;
 update btv_gamification set xp=xp+xp_gain,level=greatest(1,1+((xp+xp_gain)/500)),week_xp=week_xp+xp_gain,current_streak=case when last_activity_date=current_date then current_streak when last_activity_date=current_date-1 then current_streak+1 else 1 end,longest_streak=greatest(longest_streak,case when last_activity_date=current_date then current_streak when last_activity_date=current_date-1 then current_streak+1 else 1 end),last_activity_date=current_date,updated_at=now() where user_id=uid;
 return s;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_confirm_coin_purchase(p_reference text, p_provider_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare purchase public.btv_coin_purchases%rowtype; new_balance integer;
begin
  select * into purchase from public.btv_coin_purchases where provider_reference=p_reference for update;
  if not found then raise exception 'Purchase not found'; end if;
  if purchase.status='paid' then select balance into new_balance from public.btv_wallets where user_id=purchase.user_id; return new_balance; end if;
  if purchase.status<>'pending' then raise exception 'Purchase cannot be confirmed'; end if;
  perform public.btv_bootstrap_user(purchase.user_id);
  update public.btv_wallets set balance=balance+purchase.coin_amount,lifetime_earned=lifetime_earned+purchase.coin_amount,updated_at=now()
  where user_id=purchase.user_id returning balance into new_balance;
  update public.btv_coin_purchases set status='paid',verified_at=now(),updated_at=now() where id=purchase.id;
  insert into public.btv_wallet_transactions(user_id,amount,balance_after,transaction_type,description,reference_type,reference_id,idempotency_key)
  values(purchase.user_id,purchase.coin_amount,new_balance,'purchase','Beyond Coins purchase','coin_purchase',purchase.id,'coin-purchase:'||purchase.provider_reference)
  on conflict(user_id,idempotency_key) do nothing;
  return new_balance;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_enforce_daily_practice_limit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare max_answers integer:=10; used integer:=0; table_name text:=tg_table_name;
begin
 if new.mode<>'practice' then return new; end if;
 select coalesce((value#>>'{}')::integer,10) into max_answers from public.btv_learning_settings where key='daily_free_practice_limit';
 if table_name='cbt_attempts' then execute 'select count(*) from public.cbt_attempts where user_id=$1 and mode=''practice'' and created_at>=current_date' into used using new.user_id;
 elsif table_name='nclex_attempts' then execute 'select count(*) from public.nclex_attempts where user_id=$1 and mode=''practice'' and created_at>=current_date' into used using new.user_id;
 end if;
 if used>=max_answers then raise exception 'DAILY_PRACTICE_LIMIT:%',max_answers; end if;return new;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_get_exam_attempt(p_attempt_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare v_user uuid:=auth.uid(); v_attempt btv_exam_attempts%rowtype; v_product btv_mock_catalog%rowtype; r record; v_q jsonb; v_questions jsonb:='[]'::jsonb;
begin
 if v_user is null then raise exception using message='AUTH_REQUIRED'; end if;
 select * into v_attempt from btv_exam_attempts where id=p_attempt_id and user_id=v_user;
 if not found then raise exception using message='ATTEMPT_NOT_FOUND'; end if;
 select * into v_product from btv_mock_catalog where id=v_attempt.exam_product_id;
 for r in select * from btv_exam_attempt_questions where attempt_id=v_attempt.id order by display_order loop
   execute format('select to_jsonb(q) from public.%I q where q.id::text=$1',v_attempt.question_source) into v_q using r.question_id;
   if v_attempt.status in ('submitted','completed','refunded') then
     v_q:=v_q||jsonb_build_object('selected_answer',r.selected_answer,'is_correct',r.is_correct);
   elsif v_attempt.question_source='cbt_questions' then v_q:=v_q-'correct_option'-'explanation';
   elsif v_attempt.question_source='nclex_questions' then v_q:=v_q-'correct_options'-'rationale'-'test_strategy';
   else v_q:=v_q-'correct_answer'-'explanation'; end if;
   v_questions:=v_questions||jsonb_build_array(v_q||jsonb_build_object('display_order',r.display_order));
 end loop;
 return jsonb_build_object('attempt',to_jsonb(v_attempt),'product',to_jsonb(v_product),'questions',v_questions,'server_time',now());
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_is_admin()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
 select exists(select 1 from profiles p where p.id=auth.uid() and lower(coalesce(p.role,''))='admin')
 or exists(select 1 from btv_admin_permissions a where a.user_id=auth.uid() and a.is_active);
$function$
;

CREATE OR REPLACE FUNCTION public.btv_request_mock_refund(p_session_id uuid, p_reason text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare rid uuid;
begin
 insert into btv_mock_refund_requests(session_id,user_id,reason)
 select id,auth.uid(),left(trim(p_reason),1000) from btv_mock_sessions where id=p_session_id and user_id=auth.uid() and status in ('active','technical_failure')
 on conflict(session_id) do update set reason=excluded.reason returning id into rid;
 if rid is null then raise exception 'Session not eligible for refund review'; end if; return rid;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_start_mock(p_mock_code text, p_client_session_key text)
 RETURNS TABLE(session_id uuid, balance integer, coin_cost integer, resumed boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  uid uuid := auth.uid();
  cat public.btv_mock_catalog%rowtype;
  existing public.btv_mock_sessions%rowtype;
  w public.btv_wallets%rowtype;
  sid uuid;
  v_balance_before integer;
begin
  if uid is null then
    raise exception 'Authentication required';
  end if;

  if nullif(trim(p_client_session_key), '') is null then
    raise exception 'A session key is required';
  end if;

  perform public.btv_bootstrap_user(uid);

  select *
  into existing
  from public.btv_mock_sessions
  where user_id = uid
    and client_session_key = p_client_session_key;

  if found then
    return query
    select
      existing.id,
      (
        select bw.balance
        from public.btv_wallets bw
        where bw.user_id = uid
      ),
      existing.coin_cost,
      true;

    return;
  end if;

  select *
  into cat
  from public.btv_mock_catalog
  where code = p_mock_code
    and is_active = true;

  if not found then
    raise exception 'This mock is unavailable';
  end if;

  select *
  into w
  from public.btv_wallets
  where user_id = uid
  for update;

  if not found then
    raise exception 'Wallet not found';
  end if;

  if w.balance < cat.coin_cost then
    raise exception
      'INSUFFICIENT_BC:%:%',
      cat.coin_cost,
      w.balance;
  end if;

  v_balance_before := w.balance;

  insert into public.btv_mock_sessions(
    user_id,
    catalog_id,
    client_session_key,
    coin_cost,
    expires_at
  )
  values (
    uid,
    cat.id,
    p_client_session_key,
    cat.coin_cost,
    now() + interval '7 days'
  )
  returning id into sid;

  update public.btv_wallets
  set
    balance = balance - cat.coin_cost,
    lifetime_spent = lifetime_spent + cat.coin_cost,
    updated_at = now()
  where user_id = uid
  returning * into w;

  insert into public.btv_wallet_transactions(
    wallet_id,
    user_id,
    amount,
    balance_before,
    balance_after,
    transaction_type,
    description,
    reference_type,
    reference_id,
    idempotency_key,
    metadata
  )
  values (
    uid,
    uid,
    -cat.coin_cost,
    v_balance_before,
    w.balance,
    'mock_charge',
    cat.title || ' Mock',
    'mock_session',
    sid,
    'mock-charge:' || sid,
    jsonb_build_object(
      'mock_code', cat.code,
      'catalog_id', cat.id,
      'session_id', sid
    )
  );

  return query
  select
    sid,
    w.balance,
    cat.coin_cost,
    false;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.btv_start_paid_exam(p_product_code text, p_idempotency_key text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
 v_user uuid:=auth.uid(); v_product btv_mock_catalog%rowtype; v_wallet btv_wallets%rowtype;
 v_attempt btv_exam_attempts%rowtype; v_ids text[]; v_attempt_id uuid; v_tx_id uuid; v_before integer; v_after integer;
 v_source text; v_sql text; v_section text;
begin
 if v_user is null then raise exception using message='AUTH_REQUIRED'; end if;
 if nullif(trim(p_idempotency_key),'') is null then raise exception using message='EXAM_START_FAILED: idempotency key required'; end if;
 perform btv_bootstrap_user(v_user);
 select * into v_product from btv_mock_catalog where code=p_product_code;
 if not found then raise exception using message='PRODUCT_NOT_FOUND'; end if;
 if not v_product.is_active then raise exception using message='PRODUCT_INACTIVE'; end if;
 if coalesce(v_product.question_count,0)<=0 or coalesce(v_product.duration_minutes,0)<=0 then
   raise exception using message='PRODUCT_INACTIVE: product requires question count and duration';
 end if;
 select * into v_attempt from btv_exam_attempts where user_id=v_user and idempotency_key=p_idempotency_key;
 if found then return jsonb_build_object('attempt_id',v_attempt.id,'resumed',true,'balance',(select balance from btv_wallets where user_id=v_user),'coin_price',v_attempt.coin_price_paid,'duration_minutes',v_product.duration_minutes,'question_count',v_attempt.total_questions); end if;
 select * into v_attempt from btv_exam_attempts where user_id=v_user and exam_product_id=v_product.id and status='active' order by created_at desc limit 1;
 if found then return jsonb_build_object('attempt_id',v_attempt.id,'resumed',true,'balance',(select balance from btv_wallets where user_id=v_user),'coin_price',v_attempt.coin_price_paid,'duration_minutes',v_product.duration_minutes,'question_count',v_attempt.total_questions); end if;
 v_source:=coalesce(v_product.question_source,''); v_section:=coalesce(v_product.section,v_product.mock_category);
 if v_source not in ('cbt_questions','nclex_questions','btv_exam_questions') then raise exception using message='QUESTION_BANK_INCOMPLETE: invalid question source'; end if;
 if to_regclass('public.'||v_source) is null then raise exception using message='QUESTION_BANK_INCOMPLETE: source table is missing'; end if;
 select array_agg(question_id order by display_order,question_id) into v_ids from (select question_id,display_order from btv_exam_product_questions where exam_product_id=v_product.id and is_active order by display_order,question_id limit v_product.question_count) mapped;
 if v_product.code like 'adult_nursing_%' and coalesce(array_length(v_ids,1),0)=0 then raise exception using message='QUESTION_BANK_INCOMPLETE: Adult Nursing products require explicit reviewed question mappings'; end if;
 if coalesce(array_length(v_ids,1),0)=0 then
   if v_source='btv_exam_questions' then
     v_sql:=format('select array_agg(id::text) from (select id from public.%I where is_active=true and lower(exam_type)=lower($1) and ($2='''' or section is null or lower(section)=lower($2)) order by random() limit $3) q',v_source);
     execute v_sql into v_ids using v_product.exam_type,v_section,v_product.question_count;
   else
     v_sql:=format('select array_agg(id::text) from (select id from public.%I where is_active=true order by random() limit $1) q',v_source);
     execute v_sql into v_ids using v_product.question_count;
   end if;
 end if;
 if coalesce(array_length(v_ids,1),0)<>v_product.question_count then raise exception using message=format('QUESTION_BANK_INCOMPLETE: requires %s active questions, found %s',v_product.question_count,coalesce(array_length(v_ids,1),0)); end if;
 select * into v_wallet from btv_wallets where user_id=v_user for update;
 if v_wallet.balance<v_product.coin_cost then raise exception using message=format('INSUFFICIENT_COINS:%s:%s',v_product.coin_cost,v_wallet.balance); end if;
 v_before:=v_wallet.balance; v_after:=v_before-v_product.coin_cost;
 insert into btv_exam_attempts(user_id,exam_product_id,idempotency_key,status,question_source,question_ids,expires_at,total_questions,coin_price_paid)
 values(v_user,v_product.id,p_idempotency_key,'active',v_source,to_jsonb(v_ids),now()+make_interval(mins=>v_product.duration_minutes),v_product.question_count,v_product.coin_cost)
 returning id into v_attempt_id;
 insert into btv_exam_attempt_questions(attempt_id,question_id,display_order)
 select v_attempt_id,x.id,x.ord::integer from unnest(v_ids) with ordinality x(id,ord);
 update btv_wallets set balance=v_after,lifetime_spent=lifetime_spent+v_product.coin_cost,updated_at=now() where user_id=v_user;
 insert into btv_wallet_transactions(user_id,wallet_id,amount,balance_before,balance_after,transaction_type,source_type,reference_type,reference_id,source_id_text,description,idempotency_key,metadata)
 values(v_user,v_user,-v_product.coin_cost,v_before,v_after,'exam_charge','exam_purchase','exam_attempt',v_attempt_id,v_attempt_id::text,v_product.title,'exam:'||v_attempt_id,jsonb_build_object('product_code',v_product.code,'question_count',v_product.question_count,'duration_minutes',v_product.duration_minutes))
 returning id into v_tx_id;
 update btv_exam_attempts set wallet_transaction_id=v_tx_id where id=v_attempt_id;
 return jsonb_build_object('attempt_id',v_attempt_id,'resumed',false,'balance',v_after,'coin_price',v_product.coin_cost,'duration_minutes',v_product.duration_minutes,'question_count',v_product.question_count);
exception when unique_violation then
 select * into v_attempt from btv_exam_attempts where user_id=v_user and (idempotency_key=p_idempotency_key or (exam_product_id=v_product.id and status='active')) order by created_at desc limit 1;
 if found then return jsonb_build_object('attempt_id',v_attempt.id,'resumed',true,'balance',(select balance from btv_wallets where user_id=v_user),'coin_price',v_attempt.coin_price_paid,'duration_minutes',v_product.duration_minutes,'question_count',v_attempt.total_questions); end if;
 raise;
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_submit_paid_exam(p_attempt_id uuid, p_answers jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare v_user uuid:=auth.uid(); v_attempt btv_exam_attempts%rowtype; r record; v_selected jsonb; v_correct jsonb; v_ok boolean; v_score numeric; v_correct_count integer:=0;
begin
 if v_user is null then raise exception using message='AUTH_REQUIRED'; end if;
 select * into v_attempt from btv_exam_attempts where id=p_attempt_id and user_id=v_user for update;
 if not found then raise exception using message='ATTEMPT_NOT_FOUND'; end if;
 if v_attempt.status in ('submitted','completed') then return public.btv_get_exam_attempt(v_attempt.id); end if;
 if v_attempt.status<>'active' then raise exception using message='ATTEMPT_NOT_ACTIVE'; end if;
 for r in select * from btv_exam_attempt_questions where attempt_id=v_attempt.id order by display_order loop
   v_selected:=coalesce(p_answers->r.question_id,'null'::jsonb);
   if v_attempt.question_source='cbt_questions' then
     execute 'select to_jsonb(correct_option) from public.cbt_questions where id::text=$1' into v_correct using r.question_id;
   elsif v_attempt.question_source='nclex_questions' then
     execute 'select to_jsonb(correct_options) from public.nclex_questions where id::text=$1' into v_correct using r.question_id;
   else execute 'select correct_answer from public.btv_exam_questions where id::text=$1' into v_correct using r.question_id; end if;
   if v_attempt.question_source='nclex_questions' and jsonb_typeof(v_selected)='array' and jsonb_typeof(v_correct)='array' then
     select coalesce(array_agg(value order by value),'{}')=coalesce((select array_agg(value order by value) from jsonb_array_elements_text(v_correct)),'{}') into v_ok from jsonb_array_elements_text(v_selected);
   else v_ok:=coalesce(v_selected=v_correct,false); end if;
   if v_ok then v_correct_count:=v_correct_count+1; end if;
   update btv_exam_attempt_questions set selected_answer=v_selected,is_correct=v_ok,answered_at=now() where id=r.id;
 end loop;
 v_score:=round((v_correct_count::numeric/greatest(v_attempt.total_questions,1))*100,2);
 update btv_exam_attempts set status='completed',submitted_at=now(),score=v_score,updated_at=now() where id=v_attempt.id;
 return public.btv_get_exam_attempt(v_attempt.id)||jsonb_build_object('score',v_score,'correct_count',v_correct_count);
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_unlock_learning(p_code text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user uuid := auth.uid(); v_cost integer; v_balance integer; v_title text;
begin
  if v_user is null then raise exception 'Sign in required'; end if;
  if exists(select 1 from btv_user_learning_unlocks where user_id=v_user and unlock_code=p_code) then
    select balance into v_balance from btv_coin_wallets where user_id=v_user;
    return jsonb_build_object('unlocked',true,'already_unlocked',true,'balance',coalesce(v_balance,0));
  end if;
  select coin_cost,title into v_cost,v_title from btv_learning_unlock_catalog where code=p_code and is_active;
  if v_cost is null then raise exception 'This learning section is not available'; end if;
  insert into btv_coin_wallets(user_id,balance,lifetime_earned,lifetime_spent) values(v_user,0,0,0)
    on conflict(user_id) do nothing;
  select balance into v_balance from btv_coin_wallets where user_id=v_user for update;
  if v_balance < v_cost then raise exception 'You need % Beyond Coins to unlock this section',v_cost; end if;
  update btv_coin_wallets set balance=balance-v_cost,lifetime_spent=lifetime_spent+v_cost,updated_at=now()
    where user_id=v_user returning balance into v_balance;
  insert into btv_user_learning_unlocks(user_id,unlock_code,coin_cost) values(v_user,p_code,v_cost);
  insert into btv_coin_transactions(user_id,type,amount,balance_after,description,reference)
    values(v_user,'learning_unlock',-v_cost,v_balance,'Unlocked '||v_title,'learning:'||p_code);
  return jsonb_build_object('unlocked',true,'already_unlocked',false,'balance',v_balance,'cost',v_cost);
end $function$
;

CREATE OR REPLACE FUNCTION public.btv_use_free_practice(p_exam_type text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare v_user uuid:=auth.uid(); v_date date:=(now() at time zone 'utc')::date; v_count integer;
begin
 if v_user is null then raise exception using message='AUTH_REQUIRED'; end if;
 insert into btv_daily_practice_usage(user_id,practice_date,exam_type,questions_answered) values(v_user,v_date,lower(p_exam_type),0)
 on conflict(user_id,practice_date,exam_type) do nothing;
 select questions_answered into v_count from btv_daily_practice_usage where user_id=v_user and practice_date=v_date and exam_type=lower(p_exam_type) for update;
 if v_count>=10 then raise exception using message='DAILY_PRACTICE_LIMIT'; end if;
 update btv_daily_practice_usage set questions_answered=questions_answered+1,updated_at=now() where user_id=v_user and practice_date=v_date and exam_type=lower(p_exam_type) returning questions_answered into v_count;
 return jsonb_build_object('used',v_count,'remaining',10-v_count,'resets_at',(v_date+1)::timestamptz);
end $function$
;

